import React, { useEffect, useState } from "react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  LineChart,
  Line,
  ResponsiveContainer,
  Legend,
} from "recharts";
import "../styles/MoodTracker.css";

const colors = {
  happy: "#22c55e",
  neutral: "#3b82f6",
  sad: "#ef4444",
  anxious: "#f97316",
};

const MoodTracker = () => {
  const [moods, setMoods] = useState([]);
  const [showGraphs, setShowGraphs] = useState(false);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("moodHistory")) || [];
    setMoods(stored);
  }, []);

  const count = moods.reduce((acc, m) => {
    acc[m.mood] = (acc[m.mood] || 0) + 1;
    return acc;
  }, {});

  const barData = Object.keys(colors).map((mood) => ({
    mood,
    count: count[mood] || 0,
    fill: colors[mood],
  }));

  const lineData = moods.map((m, i) => ({
    index: i + 1,
    happy: m.mood === "happy" ? 5 : null,
    neutral: m.mood === "neutral" ? 3 : null,
    sad: m.mood === "sad" ? 1 : null,
    anxious: m.mood === "anxious" ? 2 : null,
  }));

  return (
    <div className="mood-page">
      <h1 className="title">🧠 Mood Tracker</h1>

      {/* SUMMARY CARDS */}
      <div className="summary-grid">
        <div className="card happy">😊 Happy <span>{count.happy || 0}</span></div>
        <div className="card neutral">😐 Neutral <span>{count.neutral || 0}</span></div>
        <div className="card sad">😔 Sad <span>{count.sad || 0}</span></div>
        <div className="card anxious">😟 Anxious <span>{count.anxious || 0}</span></div>
      </div>

      {/* INSIGHT */}
      <div className="insight-card">
        🌱 You’re becoming more aware of your emotions — that’s real progress.
      </div>

      {/* BUTTON */}
      <button className="toggle-btn" onClick={() => setShowGraphs(!showGraphs)}>
        {showGraphs ? "Hide Mood Analytics" : "📊 Show Mood Analytics"}
      </button>

      {/* GRAPHS */}
      {showGraphs && (
        <div className="graphs">
          <div className="graph-card">
            <h3>Mood Frequency</h3>
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={barData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="mood" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="count" />
              </BarChart>
            </ResponsiveContainer>
          </div>

          <div className="graph-card">
            <h3>Mood Journey</h3>
            <ResponsiveContainer width="100%" height={280}>
              <LineChart data={lineData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="index" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line dataKey="happy" stroke={colors.happy} />
                <Line dataKey="neutral" stroke={colors.neutral} />
                <Line dataKey="sad" stroke={colors.sad} />
                <Line dataKey="anxious" stroke={colors.anxious} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}
    </div>
  );
};

export default MoodTracker;
